#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <fcntl.h>
#include <errno.h>
#include <sys/mman.h>

int main() {
    /* Test 1: normal memory should be readable */
    char *m = malloc(4096);
    memset(m, 'x', 4096);
    int fd = open("/dev/null", O_WRONLY);
    if (fd >= 0) {
        ssize_t ret = write(fd, m, 4096);
        printf("Normal memory: write returned %zd, errno=%d\n", ret, ret == -1 ? errno : 0);
        close(fd);
    }
    free(m);

    /* Test 2: PROT_NONE memory should NOT be readable */
    void *p = mmap(NULL, 4096, PROT_NONE, MAP_PRIVATE | MAP_ANONYMOUS, -1, 0);
    if (p != MAP_FAILED) {
        fd = open("/dev/null", O_WRONLY);
        if (fd >= 0) {
            ssize_t ret = write(fd, p, 4096);
            printf("PROT_NONE memory: write returned %zd, errno=%d (%s)\n", 
                   ret, ret == -1 ? errno : 0, ret == -1 ? strerror(errno) : "ok");
            close(fd);
        }
        munmap(p, 4096);
    }

    /* Test 3: partially accessible - start with PROT_READ | PROT_WRITE, end with PROT_NONE */
    char *region = mmap(NULL, 8192, PROT_READ | PROT_WRITE, MAP_PRIVATE | MAP_ANONYMOUS, -1, 0);
    if (region != MAP_FAILED) {
        /* Protect second half */
        mprotect(region + 4096, 4096, PROT_NONE);
        memset(region, 'y', 4096);  /* First half is writable */

        fd = open("/dev/null", O_WRONLY);
        if (fd >= 0) {
            ssize_t ret = write(fd, region, 8192);
            printf("Partially accessible (8k): write returned %zd, errno=%d (%s)\n",
                   ret, ret == -1 ? errno : 0, ret == -1 ? strerror(errno) : "ok");
            close(fd);
        }
        munmap(region, 8192);
    }

    return 0;
}
EOF
